  const isInbox = labels.includes("INBOX");
  const isSelf = fromEmail === myEmail;

  const isBlockedDomain = blockedDomains.some(domain =>
    fromEmail.includes(domain)
  );

  const isBlockedKeyword = blockedKeywords.some(word =>
    fromEmail.includes(word)
  );

  const isLikelyCandidate =
    subject.includes("application") ||
    subject.includes("job") ||
    subject.includes("role") ||
    subject.includes("position");

  return (
    isInbox &&
    !isSelf &&
    !isBlockedDomain &&
    !isBlockedKeyword &&
    isLikelyCandidate
  );
});

const myEmail = "user@example.com";

function extractEmail(fromField) {
  const match = fromField.match(/<(.+?)>/);
  return match ? match[1].toLowerCase() : fromField.toLowerCase();
}

return items.map(item => {
  const messages = item.json.messages;

  let hasReplied = false;
  let candidateEmail = "";

  for (const msg of messages) {
    const labels = (msg.labels || []).map(l => l.name);
    const fromEmail = extractEmail(msg.From || "");

    // detect candidate email
    if (!labels.includes("SENT")) {
      candidateEmail = fromEmail;
    }

    // detect reply
    if (labels.includes("SENT") && fromEmail === myEmail) {
      hasReplied = true;
    }
  }

  return {
    json: {
      threadId: item.json.id,
      candidateEmail,
      hasReplied
    }
  };
});

const users = items.map(item => ({
  id: item.json.member,
  presence: item.json.presence
}));

// find active users
const activeUsers = users.filter(u => u.presence === "active");

// pick user
let selectedUser;

if (activeUsers.length > 0) {
  // pick first active (or random active)
  selectedUser = activeUsers[Math.floor(Math.random() * activeUsers.length)];
} else {
  // pick random from all
  selectedUser = users[Math.floor(Math.random() * users.length)];
}

return [
  {
    json: {
      selectedUserId: selectedUser.id,
      selectedUserPresence: selectedUser.presence
    }
  }
];
